/* ── Environment Variable Guard ────────────────────────────────
 * Firebase vars are optional (graceful fallback).
 * DM credentials are required for app functionality.
 * ─────────────────────────────────────────────────────────────── */

function requiredEnv(key: string): string {
  const value = import.meta.env[key] as string | undefined;
  if (!value || value === "changeme") {
    throw new Error(
      `Missing or unchanged required environment variable: ${key}. ` +
        "Set this in your .env file or Vercel environment variables.",
    );
  }
  return value;
}

export const ENV = {
  // DM Auth — required for app to function
  DM_USERNAME: requiredEnv("VITE_DM_USERNAME"),
  DM_PASSWORD: requiredEnv("VITE_DM_PASSWORD"),
} as const;

