/* ── Battle Maps ─────────────────────────────────────────────── */

import { useState, useMemo, useCallback } from "react";
import { useCampaignStore } from "@/stores/campaignStore";
import { useUiStore } from "@/stores/uiStore";
import { Button } from "@/components/ui/Button";
import { Badge } from "@/components/ui/Badge";
import { Modal } from "@/components/ui/Modal";
import { MapForm } from "@/components/maps/MapForm";
import { MapEditor } from "@/components/maps/MapEditor";
import type { BattleMap, MapToken, FogReveal } from "@/types";

const TOKEN_TYPE_LABELS: Record<string, string> = { player: "PC", enemy: "Enemy", npc: "NPC", custom: "Custom" };

export function BattleMaps() {
  const maps = useCampaignStore((s) => s.campaign?.battleMaps ?? []);
  const addBattleMap = useCampaignStore((s) => s.addBattleMap);
  const updateBattleMap = useCampaignStore((s) => s.updateBattleMap);

  const [selectedMap, setSelectedMap] = useState<BattleMap | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [showMapForm, setShowMapForm] = useState(false);
  const [editingMap, setEditingMap] = useState<BattleMap | undefined>();

  const filteredMaps = useMemo(() => {
    if (!searchQuery.trim()) return maps;
    const q = searchQuery.toLowerCase();
    return maps.filter((m) => m.name.toLowerCase().includes(q) || (m.notes && m.notes.toLowerCase().includes(q)));
  }, [maps, searchQuery]);

  const handleMapSubmit = (map: BattleMap) => {
    addBattleMap(map);
    setShowMapForm(false);
    useUiStore.getState().showToast({ message: `Map "${map.name}" created!`, type: "success" });
  };

  const handleTokensChange = useCallback((tokens: MapToken[]) => {
    if (!selectedMap) return;
    updateBattleMap(selectedMap.id, { tokens });
    setSelectedMap(prev => prev ? { ...prev, tokens } : null);
  }, [selectedMap, updateBattleMap]);

  const handleFogChange = useCallback((fog: FogReveal[]) => {
    if (!selectedMap) return;
    updateBattleMap(selectedMap.id, { fogOfWar: fog });
    setSelectedMap(prev => prev ? { ...prev, fogOfWar: fog } : null);
  }, [selectedMap, updateBattleMap]);

  const openForEditing = (map: BattleMap) => {
    setEditingMap(map);
    setShowMapForm(true);
  };

  return (
    <div className="mx-auto max-w-7xl space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-surface-100 md:text-2xl">Battle Maps</h2>
          <p className="mt-1 text-sm text-surface-400">{maps.length} map{maps.length !== 1 ? "s" : ""} · Deploy tactical encounters</p>
        </div>
        <Button size="sm" onClick={() => { setEditingMap(undefined); setShowMapForm(true); }}>+ New Map</Button>
      </div>

      <div className="relative max-w-md">
        <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-surface-500 text-sm">🔍</span>
        <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Search maps..."
          className="w-full rounded-lg border border-surface-700 bg-surface-800 py-2 pl-9 pr-3 text-sm text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none" />
      </div>

      {filteredMaps.length === 0 ? (
        <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-surface-700 bg-surface-850 py-16">
          <span className="text-4xl text-surface-600">{searchQuery ? "🔍" : "🗺"}</span>
          <p className="mt-3 text-sm text-surface-500">{searchQuery ? `No maps matching "${searchQuery}".` : "No battle maps yet. Create a map for your next encounter!"}</p>
        </div>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {filteredMaps.map((map) => (
            <button key={map.id} onClick={() => setSelectedMap(map)}
              className="group relative overflow-hidden rounded-xl border border-surface-700 bg-surface-850 text-left transition-all hover:border-surface-600 hover:bg-surface-800 focus-visible:outline-2 focus-visible:outline-accent-500">
              <div className="aspect-video bg-surface-800 p-2">
                <div className="relative h-full w-full">
                  {/* Background image thumbnail */}
                  {map.imageUrl ? (
                    <img src={map.imageUrl} alt="" className="absolute inset-0 h-full w-full object-cover opacity-30" />
                  ) : (
                    <div className="absolute inset-0 gap-px opacity-20"
                      style={{ display: "grid", gridTemplateColumns: `repeat(${Math.min(map.gridWidth, 8)}, 1fr)`, gridTemplateRows: `repeat(${Math.min(map.gridHeight, 6)}, 1fr)` }}>
                      {Array.from({ length: Math.min(map.gridWidth * map.gridHeight, 48) }).map((_, i) => <div key={i} className="bg-surface-500 rounded-sm" />)}
                    </div>
                  )}
                  <div className="absolute inset-0 p-1">
                    {map.tokens.filter(t => t.visible).slice(0, 8).map((token) => (
                      <div key={token.id} className="absolute h-3 w-3 rounded-full border border-white/30"
                        style={{ left: `${(token.x / map.gridWidth) * 100}%`, top: `${(token.y / map.gridHeight) * 100}%`, backgroundColor: token.color || "#8b30ff" }} title={token.label} />
                    ))}
                    {map.tokens.length > 8 && <span className="absolute bottom-1 right-1 rounded bg-surface-900/80 px-1.5 py-0.5 text-[10px] text-surface-400">+{map.tokens.length - 8} more</span>}
                  </div>
                  {map.fogOfWar.length > 0 && (
                    <span className="absolute top-1 left-1 rounded bg-surface-900/80 px-1.5 py-0.5 text-[9px] text-surface-400">🌫 {map.fogOfWar.length}</span>
                  )}
                </div>
              </div>
              <div className="p-3">
                <h3 className="font-semibold text-surface-100 group-hover:text-accent-300 transition-colors">{map.name}</h3>
                <div className="flex gap-2 mt-1.5">
                  <Badge size="xs" variant="neutral">{map.gridWidth}×{map.gridHeight}</Badge>
                  <Badge size="xs" variant="neutral">{map.tokens.length} token{map.tokens.length !== 1 ? "s" : ""}</Badge>
                </div>
              </div>
            </button>
          ))}
        </div>
      )}

      {/* Map Detail Modal with integrated MapEditor */}
      {selectedMap && (
        <Modal modalId="map-detail" title={selectedMap.name} size="xl">
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Badge variant="neutral">{selectedMap.gridWidth}×{selectedMap.gridHeight}</Badge>
                <Badge variant="neutral">{selectedMap.tokens.length} tokens</Badge>
                <Badge variant="neutral">{selectedMap.fogOfWar.length} fog zones</Badge>
              </div>
              <div className="flex gap-2">
                <Button size="xs" variant="secondary" onClick={() => openForEditing(selectedMap)}>Edit Config</Button>
                <Button size="xs" variant="ghost" onClick={() => setSelectedMap(null)}>Close</Button>
              </div>
            </div>
            <MapEditor
              map={selectedMap}
              onTokensChange={handleTokensChange}
              onFogChange={handleFogChange}
            />
            {selectedMap.notes && (
              <div className="rounded-lg border border-surface-700 bg-surface-850 p-3">
                <h4 className="text-[10px] font-semibold uppercase tracking-wider text-surface-400 mb-1">DM Notes</h4>
                <p className="text-sm text-surface-400 whitespace-pre-wrap leading-relaxed">{selectedMap.notes}</p>
              </div>
            )}
          </div>
        </Modal>
      )}

      {/* Map Form Modal */}
      {showMapForm && (
        <Modal modalId="map-form" title={editingMap ? `Edit: ${editingMap.name}` : "Create New Map"} size="lg">
          <MapForm
            initialData={editingMap}
            onSubmit={editingMap ? (map) => { updateBattleMap(map.id, map); setShowMapForm(false); } : handleMapSubmit}
            onCancel={() => { setShowMapForm(false); setEditingMap(undefined); }}
          />
        </Modal>
      )}
    </div>
  );
}

