            {selectedTags.size > 0 && <button onClick={() => setSelectedTags(new Set())} className="text-[11px] text-warrior-400 hover:text-warrior-300 transition-colors">Clear filters</button>}
          </div>
        )}
      </div>

      {filteredEntries.length === 0 ? (
        <div className="flex flex-col items-center justify-center rounded-xl border border-dashed border-surface-700 bg-surface-850 py-16">
          <span className="text-4xl text-surface-600">{searchQuery || typeFilter !== "all" || selectedTags.size > 0 ? "🔍" : "📖"}</span>
          <p className="mt-3 text-sm text-surface-500">{searchQuery || typeFilter !== "all" || selectedTags.size > 0 ? "No entries match your filters." : "Your journal is empty. Start chronicling the Arkla campaign!"}</p>
          {!searchQuery && typeFilter === "all" && selectedTags.size === 0 && (
            <Button className="mt-4" size="sm" onClick={handleCreate}>+ Create First Entry</Button>
          )}
        </div>
      ) : (
        <div className="space-y-3">
