import { useState, useEffect, useRef } from "react";
import { useHomebrewStore } from "@/stores/homebrewStore";
import { useUiStore } from "@/stores/uiStore";
import { Button } from "@/components/ui/Button";
import { Modal } from "@/components/ui/Modal";
import { ItemForm } from "@/components/homebrew/ItemForm";
import { FeatForm } from "@/components/homebrew/FeatForm";
import { SpellForm } from "@/components/homebrew/SpellForm";
import { ItemCard } from "@/components/homebrew/ItemCard";
import { FeatCard } from "@/components/homebrew/FeatCard";
import { SpellCard } from "@/components/homebrew/SpellCard";
import { ImageViewerModal } from "@/components/homebrew/ImageViewerModal";
import { exportHomebrew, importHomebrew } from "@/lib/homebrew-io";
import type { HomebrewItem, HomebrewFeat, HomebrewSpell } from "@/types/homebrew";

type Tab = "items" | "feats" | "spells";
const FORM_MODAL_ID = "homebrew-form";

export function HomebrewPanel() {
  const showToast = useUiStore((s) => s.showToast);
  const openModal = useUiStore((s) => s.openModal);
  const closeModal = useUiStore((s) => s.closeModal);
  const { items, feats, spells, addItem, updateItem, removeItem, addFeat, updateFeat, removeFeat, addSpell, updateSpell, removeSpell } = useHomebrewStore();
  const stats = useHomebrewStore((s) => s.getStats());

  const [activeTab, setActiveTab] = useState<Tab>("items");
  const [searchQuery, setSearchQuery] = useState("");
  const [editingItem, setEditingItem] = useState<HomebrewItem | undefined>();
  const [editingFeat, setEditingFeat] = useState<HomebrewFeat | undefined>();
  const [editingSpell, setEditingSpell] = useState<HomebrewSpell | undefined>();
  const [formMode, setFormMode] = useState<"create" | "edit">("create");
  const [viewingImage, setViewingImage] = useState<{ url: string; name: string } | null>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const activeModal = useUiStore((s) => s.activeModal);
  const isFormOpen = activeModal === FORM_MODAL_ID;

  const handleExport = () => {
    if (items.length === 0 && feats.length === 0 && spells.length === 0) { showToast({ message: "Nothing to export.", type: "warning" }); return; }
    exportHomebrew(items, feats, spells);
    showToast({ message: `Exported ${items.length + feats.length + spells.length} items.`, type: "success" });
  };

  const handleImport = () => importInputRef.current?.click();

  const handleImportFile = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      const text = await file.text();
      const data = JSON.parse(text);
      const result = importHomebrew(data, addItem, addFeat, addSpell);
      if (result.success) showToast({ message: `Imported ${result.itemsAdded} items, ${result.featsAdded} feats, ${result.spellsAdded} spells.`, type: "success" });
      if (result.errors.length > 0) { showToast({ message: `${result.errors.length} warning(s).`, type: "warning" }); console.warn("Import errors:", result.errors); }
    } catch { showToast({ message: "Failed to parse file.", type: "error" }); }
    e.target.value = "";
  };

  const handleLoadSample = () => {
    const sampleItem: HomebrewItem = {
      id: `sample_item_${Date.now()}`, name: "Flame Tongue Longsword", category: "weapon", rarity: "rare",
      description: "While this sword is ablaze, it deals an extra 2d6 fire damage to any target it hits.",
      flavorText: "A blade that flickers with eager flames, hungry for battle.", requiresAttunement: true,
      attunementDetails: "Must be attuned by a creature with martial weapon proficiency.", weight: 3, value: 1500, isCursed: false,
      weaponData: { weaponType: "martial melee", damageDice: "1d8", damageType: "fire", properties: ["magical", "versatile"], rangeNormal: 5, versatileDice: "1d10" },
      tags: ["weapon", "magical", "fire", "sample"], source: "Sample Data", isHomebrew: true, createdAt: Date.now(), updatedAt: Date.now(),
    };
    const sampleFeat: HomebrewFeat = {
      id: `sample_feat_${Date.now()}`, name: "Shadow Step Adept",
      description: "You have trained to move between shadows, gaining supernatural mobility in dim light and darkness.",
      prerequisites: [{ type: "ability", description: "Dexterity 13", ability: "DEX", minimumValue: 13 }, { type: "level", description: "Level 4+", minimumValue: 4 }],
      benefits: ["Teleport up to 30ft as a bonus action in dim light/darkness.", "Advantage on Stealth checks in dim light/darkness.", "Creatures you attack from dim light don't get opportunity attacks."],
      repeatable: false, tags: ["mobility", "stealth", "darkness", "sample"], source: "Sample Data", isHomebrew: true, createdAt: Date.now(), updatedAt: Date.now(),
    };
    const sampleSpell: HomebrewSpell = {
      id: `sample_spell_${Date.now()}`, name: "Chronal Shift", level: 2, school: "transmutation",
      castingTime: "reaction", ritual: false, components: ["V", "S"], concentration: false, duration: "instantaneous", range: "60 feet",
      description: "When a creature you can see makes an attack roll or ability check, you can force them to reroll the d20. The target must use the new roll.",
      atHigherLevels: "Target one additional creature per slot level above 2nd.", classes: ["sorcerer", "warlock", "wizard"],
      isHomebrew: true, source: "Sample Data", tags: ["chronomancy", "reaction", "control", "sample"], createdAt: Date.now(), updatedAt: Date.now(),
    };
    addItem(sampleItem); addFeat(sampleFeat); addSpell(sampleSpell);
    showToast({ message: "Sample data loaded!", type: "success" });
  };

  useEffect(() => {
    if (!isFormOpen) { const timer = setTimeout(() => { setEditingItem(undefined); setEditingFeat(undefined); setEditingSpell(undefined); }, 150); return () => clearTimeout(timer); }
  }, [isFormOpen]);

  const openCreateForm = () => { setFormMode("create"); setEditingItem(undefined); setEditingFeat(undefined); setEditingSpell(undefined); openModal(FORM_MODAL_ID); };
  const handleItemEdit = (item: HomebrewItem) => { setFormMode("edit"); setEditingItem(item); setEditingFeat(undefined); setEditingSpell(undefined); openModal(FORM_MODAL_ID); };
  const handleFeatEdit = (feat: HomebrewFeat) => { setFormMode("edit"); setEditingFeat(feat); setEditingItem(undefined); setEditingSpell(undefined); openModal(FORM_MODAL_ID); };
  const handleSpellEdit = (spell: HomebrewSpell) => { setFormMode("edit"); setEditingSpell(spell); setEditingItem(undefined); setEditingFeat(undefined); openModal(FORM_MODAL_ID); };

  const handleFormSubmit = (data: HomebrewItem | HomebrewFeat | HomebrewSpell) => {
    if (formMode === "create") {
      if ("weaponData" in data || "armorData" in data) addItem(data as HomebrewItem);
      else if ("prerequisites" in data) addFeat(data as HomebrewFeat);
      else if ("school" in data) addSpell(data as HomebrewSpell);
      showToast({ message: `"${data.name}" created.`, type: "success" });
    } else {
      if ("weaponData" in data || "armorData" in data) updateItem(data.id, data as HomebrewItem);
      else if ("prerequisites" in data) updateFeat(data.id, data as HomebrewFeat);
      else if ("school" in data) updateSpell(data.id, data as HomebrewSpell);
      showToast({ message: `"${data.name}" updated.`, type: "success" });
    }
    closeModal();
  };

  const handleFormCancel = () => closeModal();
  const handleDeleteItem = (id: string) => { const item = items.find((i) => i.id === id); removeItem(id); showToast({ message: `"${item?.name}" deleted.`, type: "info" }); };
  const handleDeleteFeat = (id: string) => { const feat = feats.find((f) => f.id === id); removeFeat(id); showToast({ message: `"${feat?.name}" deleted.`, type: "info" }); };
  const handleDeleteSpell = (id: string) => { const spell = spells.find((s) => s.id === id); removeSpell(id); showToast({ message: `"${spell?.name}" deleted.`, type: "info" }); };

  const formTitle = (() => {
    if (formMode === "create") {
      const labels: Record<Tab, string> = { items: "Create New Item", feats: "Create New Feat", spells: "Create New Spell" };
      return labels[activeTab];
    }
    const editLabels: Record<Tab, string> = { items: `Edit: ${editingItem?.name ?? "Item"}`, feats: `Edit: ${editingFeat?.name ?? "Feat"}`, spells: `Edit: ${editingSpell?.name ?? "Spell"}` };
    return editLabels[activeTab];
  })();

  const query = searchQuery.toLowerCase().trim();
  const filteredItems = query ? items.filter((i) => i.name.toLowerCase().includes(query) || i.tags.some((t) => t.toLowerCase().includes(query)) || i.category.toLowerCase().includes(query)) : items;
  const filteredFeats = query ? feats.filter((f) => f.name.toLowerCase().includes(query) || f.tags.some((t) => t.toLowerCase().includes(query))) : feats;
  const filteredSpells = query ? spells.filter((s) => s.name.toLowerCase().includes(query) || s.school.toLowerCase().includes(query) || s.tags.some((t) => t.toLowerCase().includes(query))) : spells;

  return (
    <div className="mx-auto max-w-6xl space-y-6">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div><h2 className="text-xl font-bold text-surface-100 md:text-2xl">Homebrew Library</h2><p className="mt-1 text-sm text-surface-400">Create and manage custom items, feats, and spells</p></div>
        <div className="flex items-center gap-2">
          <Button variant="ghost" size="xs" onClick={handleLoadSample}>📦 Sample</Button>
          <Button variant="secondary" size="sm" onClick={handleImport}>📥 Import</Button>
          <input ref={importInputRef} type="file" accept=".json" className="hidden" onChange={handleImportFile} />
          <Button variant="secondary" size="sm" onClick={handleExport}>📤 Export</Button>
          <Button onClick={openCreateForm} size="md">+ New {activeTab === "items" ? "Item" : activeTab === "feats" ? "Feat" : "Spell"}</Button>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-3">
        {(["items", "feats", "spells"] as const).map((tab) => (
          <div key={tab} className={`cursor-pointer rounded-xl border p-4 text-center transition-all ${activeTab === tab ? "border-accent-500/50 bg-accent-500/10" : "border-surface-700 bg-surface-850 hover:border-surface-600"}`} onClick={() => setActiveTab(tab)}>
            <p className="text-2xl font-bold text-surface-100">{tab === "items" ? stats.totalItems : tab === "feats" ? stats.totalFeats : stats.totalSpells}</p>
            <p className="text-xs text-surface-400 capitalize">{tab}</p>
          </div>
        ))}
      </div>

      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div className="flex gap-1 rounded-lg bg-surface-850 p-1">
          {(["items", "feats", "spells"] as const).map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`rounded-md px-4 py-2 text-sm font-medium transition-all ${activeTab === tab ? "bg-accent-600 text-white shadow-sm" : "text-surface-400 hover:text-surface-200"}`}>
              {tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
        <div className="relative w-full sm:w-72">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-surface-500 text-sm">🔍</span>
          <input type="text" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder={`Search ${activeTab}...`}
            className="w-full rounded-lg border border-surface-700 bg-surface-800 py-2 pl-9 pr-3 text-sm text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none" />
        </div>
      </div>

      {((activeTab === "items" && filteredItems.length === 0) || (activeTab === "feats" && filteredFeats.length === 0) || (activeTab === "spells" && filteredSpells.length === 0)) ? (
        <div className="flex flex-col items-center justify-center rounded-2xl border border-dashed border-surface-700 bg-surface-850 py-16 text-center">
          <span className="text-5xl text-surface-600 mb-4">{activeTab === "items" ? "📦" : activeTab === "feats" ? "⭐" : "📖"}</span>
          <h3 className="text-lg font-semibold text-surface-200 mb-1">No {activeTab} yet</h3>
          <p className="text-sm text-surface-500 mb-6 max-w-sm">{query ? `No ${activeTab} match your search.` : `Your homebrew ${activeTab} library is empty.`}</p>
          {!query && <Button onClick={openCreateForm} variant="secondary">+ Create {activeTab === "items" ? "Item" : activeTab === "feats" ? "Feat" : "Spell"}</Button>}
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3">
          {activeTab === "items" && filteredItems.map((item) => <ItemCard key={item.id} item={item} onEdit={handleItemEdit} onDelete={handleDeleteItem} onViewImage={(url) => setViewingImage({ url, name: item.name })} />)}
          {activeTab === "feats" && filteredFeats.map((feat) => <FeatCard key={feat.id} feat={feat} onEdit={handleFeatEdit} onDelete={handleDeleteFeat} />)}
          {activeTab === "spells" && filteredSpells.map((spell) => <SpellCard key={spell.id} spell={spell} onEdit={handleSpellEdit} onDelete={handleDeleteSpell} />)}
        </div>
      )}

      <Modal modalId={FORM_MODAL_ID} title={formTitle} size="lg">
        {activeTab === "items" && <ItemForm key={editingItem?.id ?? `new-item-${Date.now()}`} initialData={editingItem} onSubmit={handleFormSubmit} onCancel={handleFormCancel} />}
        {activeTab === "feats" && <FeatForm key={editingFeat?.id ?? `new-feat-${Date.now()}`} initialData={editingFeat} onSubmit={handleFormSubmit} onCancel={handleFormCancel} />}
        {activeTab === "spells" && <SpellForm key={editingSpell?.id ?? `new-spell-${Date.now()}`} initialData={editingSpell} onSubmit={handleFormSubmit} onCancel={handleFormCancel} />}
      </Modal>
      {viewingImage && <ImageViewerModal imageUrl={viewingImage.url} itemName={viewingImage.name} onClose={() => setViewingImage(null)} />}
    </div>
  );
}

