  name: string;
  cr: number;
  ac: number;
  hp: number;
  type: string;
  subType?: string;
  source: string;
}

const SRD_ENEMIES: EnemyTemplate[] = [
  { id: "bandit", name: "Bandit", cr: 0.125, ac: 12, hp: 11, type: "humanoid", subType: "any race", source: "SRD" },
