import { create } from "zustand";

export interface Toast {
  id: string;
  message: string;
  type: "success" | "error" | "info" | "warning";
  duration?: number;
}

interface UiState {
  sidebarOpen: boolean;
  activeModal: string | null;
  modalData: unknown;
  toasts: Toast[];
  /** Tracks if a page-level back button should show */
  previousRoute: string | null;

  toggleSidebar: () => void;
  setSidebarOpen: (open: boolean) => void;
  openModal: (modalId: string, data?: unknown) => void;
  closeModal: () => void;
  showToast: (toast: Omit<Toast, "id">) => void;
  dismissToast: (id: string) => void;
  setPreviousRoute: (route: string | null) => void;
}

let toastIdCounter = 0;

export const useUiStore = create<UiState>((set) => ({
  sidebarOpen: true,
  activeModal: null,
  modalData: null,
  toasts: [],
  previousRoute: null,

  toggleSidebar: () => set((state) => ({ sidebarOpen: !state.sidebarOpen })),
  setSidebarOpen: (sidebarOpen) => set({ sidebarOpen }),

  openModal: (activeModal, modalData = null) => set({ activeModal, modalData }),
  closeModal: () => set({ activeModal: null, modalData: null }),

  showToast: (toast) => {
    const id = `toast_${Date.now()}_${++toastIdCounter}`;
    const newToast: Toast = { ...toast, id };
    const duration = toast.duration ?? 4000;
    set((state) => ({ toasts: [...state.toasts, newToast] }));
    setTimeout(() => {
      set((state) => ({ toasts: state.toasts.filter((t) => t.id !== id) }));
    }, duration);
  },

  dismissToast: (id) =>
    set((state) => ({ toasts: state.toasts.filter((t) => t.id !== id) })),

  setPreviousRoute: (previousRoute) => set({ previousRoute }),
}));
