{"content": "/* ── Toast Notifications ────────────────────────────────────────
 * Stacks toasts from the uiStore. Each toast auto-dismisses after
 * its duration, or can be clicked to dismiss instantly.
 * Supports 4 types: success, error, info, warning.
 * ──────────────────────────────────────────────────────────────── */

import { useUiStore } from "@/stores/uiStore";

const TOAST_STYLES: Record<string, string> = {
  success: "border-l-rogue-500 bg-rogue-500/10 border-rogue-500/30",
  error: "border-l-warrior-500 bg-warrior-500/10 border-warrior-500/30",
  info: "border-l-mage-500 bg-mage-500/10 border-mage-500/30",
  warning: "border-l-divine-500 bg-divine-500/10 border-divine-500/30",
};

const TOAST_ICONS: Record<string, string> = {
  success: "✓",
  error: "✗",
  info: "i",
  warning: "!",
};

export function ToastContainer() {
  const toasts = useUiStore((s) => s.toasts);
  const dismissToast = useUiStore((s) => s.dismissToast);

  if (toasts.length === 0) return null;

  return (
    <div className="fixed bottom-4 right-4 z-50 flex flex-col gap-2 max-w-sm" role="status" aria-live="polite">
      {toasts.map((toast) => (
        <button
          key={toast.id}
          onClick={() => dismissToast(toast.id)}
          className={`animate-slide-up cursor-pointer rounded-lg border-l-4 px-4 py-3 text-left shadow-xl backdrop-blur-sm transition-all hover:opacity-80 ${TOAST_STYLES[toast.type] ?? TOAST_STYLES.info}`}
        >
          <div className="flex items-start gap-2">
            <span className="mt-0.5 text-sm font-bold shrink-0">
              {TOAST_ICONS[toast.type] ?? "i"}
            </span>
            <p className="text-sm text-surface-200 leading-snug">{toast.message}</p>
          </div>
        </button>
      ))}
    </div>
  );
}
