{"content": "/* ── Keyboard Shortcuts Overlay ────────────────────────────────
 * Shows a modal with all available keyboard shortcuts.
 * Press ? or F1 anywhere in the app to open/close.
 * ──────────────────────────────────────────────────────────────── */

import { useState, useEffect, useCallback } from "react";

interface Shortcut {
  key: string;
  description: string;
}

const SHORTCUTS: Shortcut[] = [
  { key: "? or F1", description: "Toggle keyboard shortcuts" },
  { key: "Esc", description: "Close modal / dismiss overlay" },
  { key: "Ctrl + K", description: "Search / quick action (if available)" },
  { key: "N", description: "New encounter (Combat Center)" },
  { key: "B", description: "Build encounter (Encounter Builder)" },
  { key: "S", description: "Start / toggle session" },
  { key: "I", description: "Open Initiative Tracker" },
  { key: "D", description: "Go to Dashboard" },
  { key: "P", description: "Go to Players" },
  { key: "J", description: "Go to Journal" },
  { key: "M", description: "Go to Battle Maps" },
  { key: "H", description: "Go to Homebrew" },
];

export function KeyboardShortcutsOverlay() {
  const [isOpen, setIsOpen] = useState(false);

  const toggle = useCallback(() => setIsOpen((o) => !o), []);

  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      // Don't trigger if user is typing in an input
      if (
        e.target instanceof HTMLInputElement ||
        e.target instanceof HTMLTextAreaElement ||
        e.target instanceof HTMLSelectElement
      ) {
        return;
      }

      if (e.key === "?" || e.key === "F1") {
        e.preventDefault();
        toggle();
      }

      if (e.key === "Escape" && isOpen) {
        setIsOpen(false);
      }
    };

    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, [toggle, isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
      <div className="mx-4 w-full max-w-lg rounded-xl border border-surface-700 bg-surface-850 shadow-2xl">
        <div className="flex items-center justify-between border-b border-surface-700 px-5 py-4">
          <h2 className="font-bold text-surface-100">Keyboard Shortcuts</h2>
          <button
            onClick={() => setIsOpen(false)}
            className="text-sm text-surface-500 hover:text-surface-300 transition-colors"
            aria-label="Close keyboard shortcuts"
          >
            ✕
          </button>
        </div>
        <div className="max-h-96 overflow-y-auto p-5 space-y-2">
          {SHORTCUTS.map((shortcut) => (
            <div
              key={shortcut.key}
              className="flex items-center justify-between rounded-lg bg-surface-800 px-4 py-2.5"
            >
              <span className="text-sm text-surface-300">{shortcut.description}</span>
              <kbd className="rounded-md border border-surface-600 bg-surface-700 px-2.5 py-1 text-xs font-mono font-medium text-accent-400 shadow-sm">
                {shortcut.key}
              </kbd>
            </div>
          ))}
        </div>
        <div className="border-t border-surface-700 px-5 py-3 text-center">
          <p className="text-xs text-surface-500">Press <kbd className="rounded border border-surface-600 bg-surface-800 px-1.5 py-0.5 text-[10px] font-mono text-surface-400">?</kbd> or <kbd className="rounded border border-surface-600 bg-surface-800 px-1.5 py-0.5 text-[10px] font-mono text-surface-400">F1</kbd> to toggle this overlay</p>
        </div>
      </div>
    </div>
  );
}
