{"content": "/* ── useImageFallback Hook ─────────────────────────────────────
 * Prevents broken image icons by providing a fallback state.
 * Returns [imgRef, hasError] for use in any <img> tag.
 * ─────────────────────────────────────────────────────────────── */

import { useState, useCallback } from "react";

interface ImageFallbackResult {
  /** Handler for onError on an <img> tag */
  handleError: () => void;
  /** Whether the image failed to load */
  hasError: boolean;
  /** Reset the error state */
  reset: () => void;
}

export function useImageFallback(): ImageFallbackResult {
  const [hasError, setHasError] = useState(false);

  const handleError = useCallback(() => {
    setHasError(true);
  }, []);

  const reset = useCallback(() => {
    setHasError(false);
  }, []);

  return { handleError, hasError, reset };
}

/** Generate a placeholder gradient based on a string (e.g., character name) */
export function getImagePlaceholder(name: string): string {
  const colors = [
    "from-accent-600/40 to-accent-800/40",
    "from-mage-600/40 to-mage-800/40",
    "from-warrior-600/40 to-warrior-800/40",
    "from-divine-600/40 to-divine-800/40",
    "from-rogue-600/40 to-rogue-800/40",
  ];
  const index = name.split("").reduce((acc, char) => acc + char.charCodeAt(0), 0);
  return colors[index % colors.length];
}
