{"content": "/* ── ImageWithFallback ─────────────────────────────────────────
 * A safe <img> wrapper that shows a placeholder on load failure.
 * ─────────────────────────────────────────────────────────────── */

import { useState, type ImgHTMLAttributes } from "react";

interface ImageWithFallbackProps extends ImgHTMLAttributes<HTMLImageElement> {
  /** Alt text (required for accessibility) */
  alt: string;
  /** Optional CSS classes for the placeholder */
  placeholderClass?: string;
  /** Optional emoji/icon to show on error */
  fallbackIcon?: string;
}

export function ImageWithFallback({
  alt,
  src,
  placeholderClass = "",
  fallbackIcon = "✨",
  className = "",
  ...props
}: ImageWithFallbackProps) {
  const [hasError, setHasError] = useState(false);

  if (!src || hasError) {
    return (
      <div
        className={`flex items-center justify-center bg-surface-800 text-surface-500 ${placeholderClass || className}`}
        role="img"
        aria-label={alt}
      >
        <span className="text-2xl">{fallbackIcon}</span>
      </div>
    );
  }

  return (
    <img
      src={src}
      alt={alt}
      className={className}
      onError={() => setHasError(true)}
      loading="lazy"
      {...props}
    />
  );
}
