          </div>
          <div className="flex items-center gap-3">
            {sessionStarted && <div className="rounded-md bg-surface-800 px-3 py-1.5 text-center"><p className="text-xs text-surface-500">{hours > 0 ? `${hours}h ` : ""}{minutes}m {secs.toString().padStart(2, "0")}s</p></div>}
            {!sessionStarted ? <Button size="sm" onClick={startSession}>▶ Start Session</Button> : <Button variant="danger" size="sm" onClick={endSession}>■ End Session</Button>}
