          addCombatant({
            name: label,
            type: "enemy",
            initiative: 0,
            initiativeBonus: template.initMod,
            armorClass: template.ac,
            hitPoints: { current: template.hp, max: template.hp, temporary: 0 },
            maxHitPoints: template.hp,
            temporaryHitPoints: 0,
            statusEffects: [],
            isDead: false,
            isConcentrating: false,
            concentrationOn: undefined,
            notes: undefined,
            color: "#e74c3c",
          });
          totalLoaded++;
        }
      }
