                      className={`rounded-lg border px-3 py-2.5 text-left text-sm transition-all ${liveSession.phase === phase ? "border-accent-500 bg-accent-500/10 text-accent-300" : "border-surface-700 bg-surface-800 text-surface-400 hover:border-surface-600 hover:text-surface-200"}`}>
