                {!sceneInput && !mapUrlInput && !announcementInput && <p className="text-sm text-surface-500 italic">Players will see your scene description, map, and announcements here once you push them.</p>}
              </div>
            </div>

            <div className="rounded-xl border border-surface-700 bg-surface-850 p-4">
              <h4 className="mb-3 text-xs font-semibold uppercase tracking-wider text-surface-400">Rest Tracker</h4>
              <div className="grid grid-cols-2 gap-3">
