                  {lastShortRest && <p className="mt-1 text-[11px] text-surface-500">Last: {lastShortRest}</p>}
                </div>
                <div className="rounded-lg border border-surface-700 bg-surface-800 p-3">
                  <div className="flex items-center justify-between"><span className="text-sm font-medium text-surface-200">Long Rest</span><Button size="xs" variant="secondary" onClick={() => recordRest("long")}>Record</Button></div>
