                </div>
              </div>
            </div>

            {activeEncounter && activeEncounter.phase === "active" && (
              <div className="rounded-xl border border-warrior-500/30 bg-warrior-500/5 p-4">
                <div className="flex items-center gap-2 mb-2">
                  <span className="text-lg">⚔️</span>
                  <h4 className="text-sm font-semibold text-surface-100">Active Combat: {activeEncounter.name}</h4>
                  <span className="rounded bg-warrior-500/20 px-2 py-0.5 text-[11px] font-medium text-warrior-400">R{activeEncounter.round}</span>
                </div>
                <p className="text-xs text-surface-400">{activeEncounter.combatants.filter((c) => !c.isDead).length} combatants remaining · {activeEncounter.combatants.filter((c) => c.isDead).length} defeated</p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
