{"content": "/* ── Combat Log Panel ──────────────────────────────────────────
 * Displays combat log entries with filter/sort/export and undo.
 * Supports relative timestamps and combatant name search.
 * ─────────────────────────────────────────────────────────────── */

import { useState, useMemo } from "react";
import type { CombatLogEntry } from "@/types/combat";
import { useCombatStore } from "@/stores/combatStore";
import { Button } from "@/components/ui/Button";

interface CombatLogPanelProps {
  log: CombatLogEntry[];
}

type LogFilter = "all" | "damage" | "heal" | "status" | "round_start";

function relativeTime(timestamp: number): string {
  const diff = Date.now() - timestamp;
  const seconds = Math.floor(diff / 1000);
  if (seconds < 60) return `${seconds}s ago`;
  const minutes = Math.floor(seconds / 60);
  if (minutes < 60) return `${minutes}m ago`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ago`;
  return `${Math.floor(hours / 24)}d ago`;
}

const LOG_STYLES: Record<string, string> = {
  damage: "border-l-warrior-500/50 bg-warrior-500/5",
  heal: "border-l-divine-500/50 bg-divine-500/5",
  death: "border-l-warrior-500 bg-warrior-500/10 font-semibold",
  status: "border-l-mage-500/50 bg-mage-500/5",
  round_start: "border-l-accent-500/50 bg-accent-500/5",
  note: "border-l-surface-600/50 bg-surface-800",
};

export function CombatLogPanel({ log }: CombatLogPanelProps) {
  const clearLog = useCombatStore((s) => s.clearLog);
  const removeLastLogEntry = useCombatStore((s) => s.removeLastLogEntry);
  const [filter, setFilter] = useState<LogFilter>("all");
  const [searchQuery, setSearchQuery] = useState("");

  const filteredLog = useMemo(() => {
    let entries = [...log];

    if (filter !== "all") {
      entries = entries.filter((e) => e.type === filter);
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      entries = entries.filter(
        (e) =>
          e.actorName.toLowerCase().includes(q) ||
          (e.targetName ?? "").toLowerCase().includes(q) ||
          e.description.toLowerCase().includes(q),
      );
    }

    return entries;
  }, [log, filter, searchQuery]);

  const filters: { key: LogFilter; label: string }[] = [
    { key: "all", label: "All" },
    { key: "damage", label: "Damage" },
    { key: "heal", label: "Heal" },
    { key: "status", label: "Status" },
    { key: "round_start", label: "Round" },
  ];

  return (
    <div className="rounded-xl border border-surface-700 bg-surface-850">
      <div className="flex items-center justify-between border-b border-surface-700 px-4 py-3">
        <h4 className="text-xs font-semibold uppercase tracking-wider text-surface-400">Combat Log</h4>
        <div className="flex items-center gap-1">
          {log.length > 0 && (
            <>
              <Button size="xs" variant="ghost" onClick={removeLastLogEntry} title="Undo last action">↩</Button>
              <Button size="xs" variant="ghost" onClick={clearLog} title="Clear log">✕</Button>
            </>
          )}
        </div>
      </div>

      {log.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-8">
          <span className="text-2xl text-surface-600">📋</span>
          <p className="mt-2 text-sm text-surface-500">Combat log is empty.</p>
          <p className="text-xs text-surface-600">Actions will appear here as combat progresses.</p>
        </div>
      ) : (
        <div className="space-y-2 p-3">
          {/* Search + Filter */}
          <div className="flex gap-2">
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search combatant..."
              className="flex-1 rounded-md border border-surface-700 bg-surface-800 px-2.5 py-1.5 text-xs text-surface-100 placeholder:text-surface-500 focus:border-accent-500 focus:outline-none"
            />
          </div>
          <div className="flex gap-1 flex-wrap">
            {filters.map((f) => (
              <button
                key={f.key}
                onClick={() => setFilter(f.key)}
                className={`rounded-md px-2 py-1 text-[11px] font-medium transition-colors ${
                  filter === f.key
                    ? "bg-accent-500/15 text-accent-400"
                    : "text-surface-500 hover:bg-surface-800 hover:text-surface-300"
                }`}
              >
                {f.label}
              </button>
            ))}
          </div>

          {/* Log Entries */}
          <div className="space-y-1 max-h-[400px] overflow-y-auto pr-1">
            {filteredLog.length === 0 ? (
              <p className="py-4 text-center text-xs text-surface-500">No entries match filter.</p>
            ) : (
              filteredLog.map((entry) => (
                <div
                  key={entry.id}
                  className={`rounded-lg border-l-2 px-3 py-2 text-sm ${LOG_STYLES[entry.type] ?? "border-l-surface-600 bg-surface-800"}`}
                >
                  <div className="flex items-start justify-between gap-2">
                    <span className="text-xs text-surface-300 leading-relaxed">{entry.description}</span>
                    <span className="shrink-0 text-[10px] text-surface-500 whitespace-nowrap">
                      {relativeTime(entry.timestamp)}
                    </span>
                  </div>
                  {entry.value !== undefined && (
                    <span className="text-[10px] text-surface-500 font-medium">{entry.value > 0 ? `${entry.value}` : ""}</span>
                  )}
                </div>
              ))
            )}
          </div>

          {/* Export JSON button */}
          {log.length > 0 && (
            <div className="flex justify-end pt-1">
              <Button
                size="xs"
                variant="ghost"
                onClick={() => {
                  const blob = new Blob([JSON.stringify(log, null, 2)], { type: "application/json" });
                  const url = URL.createObjectURL(blob);
                  const a = document.createElement("a");
                  a.href = url;
                  a.download = `combat-log-${Date.now()}.json`;
                  a.click();
                  URL.revokeObjectURL(url);
                }}
              >
                📥 Export JSON
              </Button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
