  const handleFormSubmit = (data: HomebrewItem | HomebrewFeat | HomebrewSpell) => {
    if (formMode === "create") {
      if ("weaponData" in data || "armorData" in data) addItem(data as HomebrewItem);
      else if ("prerequisites" in data) addFeat(data as HomebrewFeat);
      else if ("school" in data) addSpell(data as HomebrewSpell);
      showToast({ message: `"${data.name}" created.`, type: "success" });
    } else {
      if ("weaponData" in data || "armorData" in data) updateItem(data.id, data as HomebrewItem);
      else if ("prerequisites" in data) updateFeat(data.id, data as HomebrewFeat);
      else if ("school" in data) updateSpell(data.id, data as HomebrewSpell);
