  addCombatant: (data) => {
    const id = uid("combatant");
    const combatant: Combatant = { ...data, id };
    const encounter = get().activeEncounter;
    if (!encounter) return id;

    const updated = {
      ...encounter,
      combatants: [...encounter.combatants, combatant],
    };
    set({ activeEncounter: updated });
