    const encounter = get().activeEncounter;
    if (!encounter) return;
    set({
      activeEncounter: {
        ...encounter,
        combatants: encounter.combatants.filter((c) => c.id !== combatantId),
      },
    });
  },

  updateCombatant: (combatantId, updates) => {
    const encounter = get().activeEncounter;
    if (!encounter) return;
    set({
      activeEncounter: {
