/* ── Firebase Initialization ───────────────────────────────────
 * Gracefully initializes Firebase if config is present.
 * Falls back gracefully if env vars are not set (e.g., during development).
 * ─────────────────────────────────────────────────────────────── */

import { initializeApp, type FirebaseOptions } from "firebase/app";
import { getFirestore, connectFirestoreEmulator } from "firebase/firestore";
import { getAuth, connectAuthEmulator } from "firebase/auth";
import { getStorage, connectStorageEmulator } from "firebase/storage";

const apiKey = import.meta.env.VITE_FIREBASE_API_KEY as string | undefined;

let db: ReturnType<typeof getFirestore> | null = null;
let auth: ReturnType<typeof getAuth> | null = null;
let storage: ReturnType<typeof getStorage> | null = null;

if (apiKey && apiKey !== "your_api_key_here") {
  const firebaseConfig: FirebaseOptions = {
    apiKey,
    authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
    projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
    storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
    messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
    appId: import.meta.env.VITE_FIREBASE_APP_ID,
  };

  const app = initializeApp(firebaseConfig);
  db = getFirestore(app);
  auth = getAuth(app);
  storage = getStorage(app);

  /* ── Emulator Connection (Dev Mode) ─────────────────────── */
  if (import.meta.env.DEV) {
    connectFirestoreEmulator(db, "localhost", 8080);
    connectAuthEmulator(auth, "http://localhost:9099", { disableWarnings: true });
    connectStorageEmulator(storage, "localhost", 9199);
  }
} else {
  console.info(
    "Firebase not configured. Run the Firebase emulator or set VITE_FIREBASE_* env vars.",
  );
}

export { db, auth, storage };
export const isFirebaseConfigured = !!db;

export default null;
